 use jwxt;
#代码开始
#题目1
select * from course
where courseid in (
    select distinct sc.courseid
    from score sc
);
#题目2
select * from course
where courseid not in (
    select distinct courseid
    from score sc
);
#题目3
select * from student
where studentid not in (
    select sc.studentid
    from score sc
    where sc.courseid in (
        select distinct c.courseid
        from course c
        where c.coursename = '高等数学'
    )
);
